sql:
SELECT coin_id, denomination
FROM coins
WHERE metal_composition = 'Gold' AND year > 1950;

SELECT c.description, c.denomination, ah.house_name 
FROM coins c
JOIN auction_houses ah ON c.auction_house_id = ah.auction_house_id;

SELECT 
    (SELECT SUM(sell_price) FROM sales) AS total_sales_price, 
    (SELECT AVG(rating) FROM auction_houses) AS average_auction_house_rating;

SELECT c.coin_id, c.description, ah.house_name, ah.location
FROM coins c
JOIN auction_houses ah ON c.auction_house_id = ah.auction_house_id;

SELECT *
FROM coins
WHERE coin_id = (SELECT MAX(coin_id) FROM coins);

SELECT COUNT(DISTINCT coin_id) AS offered_coins_without_sale
FROM bids
WHERE coin_id NOT IN (
    SELECT coin_id
    FROM sales
);

SELECT AVG(grade) AS average_grade
FROM coins
WHERE year < 1900;

external_knowledge:
- 'Annual harvests' refers to the total sales data grouped by year; 
- 'coins reaped' represents the total number of coins sold; 
- 'total revenue gathered' corresponds to the total revenue from sales.

